<div class="wdl-library"><table class="wdl-document-table"><thead><tr><th></th><th>Название</th><th>Категория</th><th>Формат</th><th>Версия</th><th>Дата</th><th></th></tr></thead><tbody><?php if($data['query']->have_posts()): while($data['query']->have_posts()):$data['query']->the_post(); $u=get_post_meta(get_the_ID(),'_wdl_file_url',true); ?><tr><td><?php echo $data['helpers']->get_thumb_or_icon(get_the_ID(),$u,'thumbnail'); ?></td><td><?php the_title();?></td><td><?php echo esc_html(wp_strip_all_tags(get_the_term_list(get_the_ID(),'wdl_document_category','',', ')));?></td><td><?php echo esc_html(strtoupper($data['helpers']->get_file_ext($u)));?></td><td><?php echo esc_html(get_post_meta(get_the_ID(),'_wdl_version',true));?></td><td><?php echo esc_html(get_post_meta(get_the_ID(),'_wdl_updated_date',true));?></td><td><?php if($u):?><a class="wdl-button wdl-button-open" href="<?php echo esc_url(get_permalink());?>">Открыть</a> <a class="wdl-button wdl-button-download" href="<?php echo esc_url($u);?>" download>Скачать</a><?php endif;?></td></tr><?php endwhile; else: ?><tr><td colspan="7">Документы не найдены</td></tr><?php endif; ?></tbody></table></div>
